package com.citybus.platform.service;

import com.citybus.platform.dto.request.LoginRequest;
import com.citybus.platform.dto.request.RegisterRequest;
import com.citybus.platform.dto.response.LoginResponse;
import com.citybus.platform.entity.User;
import com.citybus.platform.exception.BusinessException;
import com.citybus.platform.repository.UserRepository;
import com.citybus.platform.security.JwtTokenProvider;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Slf4j
public class AuthService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final AuthenticationManager authenticationManager;
    private final JwtTokenProvider tokenProvider;
    private final AuditService auditService;

    public LoginResponse login(LoginRequest request) {
        Authentication auth = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(request.getUsername(), request.getPassword()));
        User user = (User) auth.getPrincipal();
        String token = tokenProvider.generateToken(auth);
        log.info("User logged in: {}", user.getUsername());
        auditService.log("LOGIN", "USER", user.getId(), user.getId(), null);
        return new LoginResponse(token, user.getId(), user.getUsername(),
                user.getRole().name(), user.getDisplayName());
    }

    @Transactional
    public LoginResponse register(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new BusinessException("Username already taken");
        }
        if (request.getPassword().length() < 8) {
            throw new BusinessException("Password must be at least 8 characters");
        }
        User user = new User();
        user.setUsername(request.getUsername());
        user.setPassword(passwordEncoder.encode(request.getPassword()));
        user.setDisplayName(request.getDisplayName() != null ?
                request.getDisplayName() : request.getUsername());
        user.setRole(User.UserRole.PASSENGER);
        userRepository.save(user);

        String token = tokenProvider.generateToken(user.getUsername());
        log.info("New passenger registered: {}", user.getUsername());
        return new LoginResponse(token, user.getId(), user.getUsername(),
                user.getRole().name(), user.getDisplayName());
    }

    public User getCurrentUser(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "User not found"));
    }
}

package com.citybus.platform.service;

import com.citybus.platform.dto.request.ReservationRequest;
import com.citybus.platform.dto.response.ReservationResponse;
import com.citybus.platform.entity.*;
import com.citybus.platform.exception.BusinessException;
import com.citybus.platform.repository.*;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Slf4j
public class ReservationService {

    private final ReservationRepository reservationRepository;
    private final UserRepository userRepository;
    private final BusRouteRepository routeRepository;
    private final BusStopRepository stopRepository;
    private final NotificationService notificationService;

    @Transactional
    public ReservationResponse create(Long userId, ReservationRequest req) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "User not found"));
        BusRoute route = routeRepository.findById(req.getRouteId())
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Route not found"));
        BusStop stop = stopRepository.findById(req.getStopId())
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Stop not found"));

        if (stop.getRoute() == null || !stop.getRoute().getId().equals(route.getId())) {
            throw new BusinessException(HttpStatus.BAD_REQUEST, "Stop does not belong to this route");
        }

        Reservation reservation = new Reservation();
        reservation.setUser(user);
        reservation.setRoute(route);
        reservation.setStop(stop);
        reservation.setScheduledTime(req.getScheduledTime());
        reservation.setStatus(Reservation.ReservationStatus.CONFIRMED);
        reservationRepository.save(reservation);

        notificationService.createNotification(userId, Notification.NotificationType.RESERVATION_SUCCESS,
                "Reservation Confirmed",
                "Your reservation for " + route.getRouteNumber() + " at " + stop.getNameEn()
                        + " on " + req.getScheduledTime() + " is confirmed.",
                reservation.getId());

        log.info("Reservation created: id={} user={} route={}", reservation.getId(), userId, route.getRouteNumber());
        return toResponse(reservation);
    }

    public Page<ReservationResponse> getMyReservations(Long userId, Pageable pageable) {
        return reservationRepository.findByUserIdOrderByCreatedAtDesc(userId, pageable)
                .map(this::toResponse);
    }

    @Transactional
    public ReservationResponse cancel(Long reservationId, Long userId) {
        Reservation reservation = reservationRepository.findById(reservationId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Reservation not found"));
        if (!reservation.getUser().getId().equals(userId)) {
            throw new BusinessException(HttpStatus.FORBIDDEN, "Access denied");
        }
        if (reservation.getStatus() != Reservation.ReservationStatus.CONFIRMED) {
            throw new BusinessException(HttpStatus.BAD_REQUEST, "Only confirmed reservations can be cancelled");
        }
        reservation.setStatus(Reservation.ReservationStatus.CANCELLED);
        reservationRepository.save(reservation);
        log.info("Reservation cancelled: id={}", reservationId);
        return toResponse(reservation);
    }

    private ReservationResponse toResponse(Reservation r) {
        return new ReservationResponse(
                r.getId(),
                r.getRoute().getId(), r.getRoute().getRouteNumber(), r.getRoute().getName(),
                r.getStop().getId(), r.getStop().getNameEn(), r.getStop().getNameCn(),
                r.getScheduledTime(), r.getStatus().name(), r.getCreatedAt()
        );
    }
}

package com.citybus.platform.service;

import com.citybus.platform.dto.request.NotificationPrefRequest;
import com.citybus.platform.dto.response.NotificationResponse;
import com.citybus.platform.entity.*;
import com.citybus.platform.exception.BusinessException;
import com.citybus.platform.repository.*;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalTime;
import java.util.List;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class NotificationService {

    private final NotificationRepository notificationRepository;
    private final NotificationPreferenceRepository prefRepository;
    private final NotificationTemplateRepository templateRepository;
    private final UserRepository userRepository;
    private final BusRouteRepository routeRepository;
    private final BusStopRepository stopRepository;

    public Page<NotificationResponse> getNotifications(Long userId, Pageable pageable) {
        return notificationRepository.findByUserIdOrderByCreatedAtDesc(userId, pageable)
                .map(this::toResponse);
    }

    public long getUnreadCount(Long userId) {
        return notificationRepository.countByUserIdAndReadFalse(userId);
    }

    @Transactional
    public void markRead(Long notificationId, Long userId) {
        Notification notification = notificationRepository.findById(notificationId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Notification not found"));
        if (!notification.getUser().getId().equals(userId)) {
            throw new BusinessException(HttpStatus.FORBIDDEN, "Access denied");
        }
        notification.setRead(true);
        notificationRepository.save(notification);
    }

    @Transactional
    public void markAllRead(Long userId) {
        notificationRepository.markAllReadByUserId(userId);
    }

    @Transactional
    public NotificationPreference savePreference(Long userId, NotificationPrefRequest req) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "User not found"));

        BusRoute route = req.getRouteId() != null ?
                routeRepository.findById(req.getRouteId()).orElse(null) : null;
        BusStop stop = req.getStopId() != null ?
                stopRepository.findById(req.getStopId()).orElse(null) : null;

        NotificationPreference pref = prefRepository
                .findByUserIdAndRouteIdAndStopId(userId, req.getRouteId(), req.getStopId())
                .orElse(new NotificationPreference());

        pref.setUser(user);
        pref.setRoute(route);
        pref.setStop(stop);
        pref.setReminderMinutes(req.getReminderMinutes() != null ? req.getReminderMinutes() : 10);
        pref.setEnabled(req.isEnabled());
        pref.setDndEnabled(req.isDndEnabled());
        if (req.isDndEnabled()) {
            pref.setDndStart(req.getDndStart() != null ? LocalTime.parse(req.getDndStart()) : null);
            pref.setDndEnd(req.getDndEnd() != null ? LocalTime.parse(req.getDndEnd()) : null);
        }
        return prefRepository.save(pref);
    }

    public List<NotificationPreference> getPreferences(Long userId) {
        return prefRepository.findByUserId(userId);
    }

    @Transactional
    public Notification createNotification(Long userId, Notification.NotificationType type,
                                           String title, String content, Long entityId) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "User not found"));

        String maskedContent = maskSensitiveContent(content, type);

        Notification notification = new Notification();
        notification.setUser(user);
        notification.setType(type);
        notification.setTitle(title);
        notification.setContent(maskedContent);
        notification.setEntityId(entityId);
        log.info("Creating notification for user={} type={}", userId, type);
        return notificationRepository.save(notification);
    }

    private String maskSensitiveContent(String content, Notification.NotificationType type) {
        if (type == Notification.NotificationType.TASK_ESCALATED) {
            return content.replaceAll("\\b\\d{11}\\b", "***-****-****");
        }
        return content;
    }

    private NotificationResponse toResponse(Notification n) {
        return new NotificationResponse(n.getId(), n.getType().name(), n.getTitle(),
                n.getContent(), n.isRead(), n.getEntityId(), n.getCreatedAt());
    }
}
package com.citybus.platform.service;

import com.citybus.platform.dto.request.WorkflowApprovalRequest;
import com.citybus.platform.dto.request.WorkflowTaskRequest;
import com.citybus.platform.dto.response.WorkflowApprovalResponse;
import com.citybus.platform.dto.response.WorkflowTaskResponse;
import com.citybus.platform.entity.*;
import com.citybus.platform.exception.BusinessException;
import com.citybus.platform.repository.*;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.concurrent.atomic.AtomicLong;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class WorkflowService {

    private final WorkflowTaskRepository taskRepository;
    private final WorkflowApprovalRepository approvalRepository;
    private final UserRepository userRepository;
    private final NotificationService notificationService;

    private static final AtomicLong TASK_COUNTER = new AtomicLong(1000);

    @Transactional
    public WorkflowTaskResponse createTask(Long creatorId, WorkflowTaskRequest req) {
        User creator = userRepository.findById(creatorId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "User not found"));

        User assignedTo = null;
        if (req.getAssignedToId() != null) {
            assignedTo = userRepository.findById(req.getAssignedToId())
                    .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Assigned user not found"));
        }

        WorkflowTask task = new WorkflowTask();
        task.setTaskNumber(generateTaskNumber(req.getType()));
        task.setType(req.getType());
        task.setTitle(req.getTitle());
        task.setDescription(req.getDescription());
        task.setStatus(WorkflowTask.TaskStatus.PENDING);
        task.setCreatedBy(creator);
        task.setAssignedTo(assignedTo);
        task.setDeadline(req.getDeadline());
        task.setPayload(req.getPayload());
        task.setEscalated(false);
        taskRepository.save(task);

        if (assignedTo != null) {
            notificationService.createNotification(assignedTo.getId(),
                    Notification.NotificationType.TASK_ASSIGNED,
                    "New Task Assigned: " + task.getTaskNumber(),
                    "You have been assigned task: " + task.getTitle(), task.getId());
        }

        log.info("Workflow task created: {} by user={}", task.getTaskNumber(), creatorId);
        return toResponse(task);
    }

    public Page<WorkflowTaskResponse> getMyTasks(Long userId, Pageable pageable) {
        return taskRepository.findByAssignedToIdOrderByCreatedAtDesc(userId, pageable).map(this::toResponse);
    }

    public Page<WorkflowTaskResponse> getTasksByStatus(WorkflowTask.TaskStatus status, Pageable pageable) {
        return taskRepository.findByStatusOrderByCreatedAtDesc(status, pageable).map(this::toResponse);
    }

    public WorkflowTaskResponse getTask(Long taskId) {
        return toResponse(findTask(taskId));
    }

    @Transactional
    public WorkflowApprovalResponse processApproval(Long taskId, Long approverId, WorkflowApprovalRequest req) {
        WorkflowTask task = findTask(taskId);
        User approver = userRepository.findById(approverId)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "User not found"));

        if (task.getStatus() == WorkflowTask.TaskStatus.APPROVED
                || task.getStatus() == WorkflowTask.TaskStatus.CANCELLED) {
            throw new BusinessException(HttpStatus.BAD_REQUEST, "Task is already finalized");
        }

        WorkflowApproval approval = new WorkflowApproval();
        approval.setTask(task);
        approval.setApprover(approver);
        approval.setAction(req.getAction());
        approval.setComment(req.getComment());
        approvalRepository.save(approval);

        switch (req.getAction().toUpperCase()) {
            case "APPROVE" -> task.setStatus(WorkflowTask.TaskStatus.APPROVED);
            case "REJECT" -> task.setStatus(WorkflowTask.TaskStatus.REJECTED);
            case "RETURN" -> task.setStatus(WorkflowTask.TaskStatus.RETURNED);
            default -> throw new BusinessException(HttpStatus.BAD_REQUEST, "Unknown action: " + req.getAction());
        }
        taskRepository.save(task);
        log.info("Task {} action={} by user={}", task.getTaskNumber(), req.getAction(), approverId);

        return new WorkflowApprovalResponse(approval.getId(), task.getId(),
                approver.getUsername(), approval.getAction(), approval.getComment(), approval.getCreatedAt());
    }

    public List<WorkflowApprovalResponse> getApprovals(Long taskId) {
        findTask(taskId);
        return approvalRepository.findByTaskIdOrderByCreatedAtAsc(taskId).stream()
                .map(a -> new WorkflowApprovalResponse(a.getId(), taskId,
                        a.getApprover().getUsername(), a.getAction(), a.getComment(), a.getCreatedAt()))
                .collect(Collectors.toList());
    }

    @Transactional
    public int escalateOverdueTasks(LocalDateTime threshold) {
        List<WorkflowTask> tasks = taskRepository.findTasksToEscalate(threshold);
        tasks.forEach(t -> {
            t.setEscalated(true);
            t.setStatus(WorkflowTask.TaskStatus.ESCALATED);
            taskRepository.save(t);
            if (t.getAssignedTo() != null) {
                notificationService.createNotification(t.getAssignedTo().getId(),
                        Notification.NotificationType.TASK_ESCALATED,
                        "Task Escalated: " + t.getTaskNumber(),
                        "Task " + t.getTaskNumber() + " has been escalated due to inactivity.", t.getId());
            }
        });
        log.info("Escalated {} tasks", tasks.size());
        return tasks.size();
    }

    private WorkflowTask findTask(Long id) {
        return taskRepository.findById(id)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Task not found"));
    }

    private String generateTaskNumber(WorkflowTask.TaskType type) {
        String prefix = switch (type) {
            case ROUTE_DATA_CHANGE -> "RDC";
            case REMINDER_RULE_CONFIG -> "RRC";
            case ABNORMAL_DATA_REVIEW -> "ADR";
        };
        return prefix + "-" + DateTimeFormatter.ofPattern("yyyyMMdd").format(LocalDateTime.now())
                + "-" + String.format("%04d", TASK_COUNTER.incrementAndGet());
    }

    private WorkflowTaskResponse toResponse(WorkflowTask t) {
        return new WorkflowTaskResponse(
                t.getId(), t.getTaskNumber(), t.getType().name(), t.getTitle(), t.getDescription(),
                t.getStatus().name(),
                t.getAssignedTo() != null ? t.getAssignedTo().getUsername() : null,
                t.getAssignedTo() != null ? t.getAssignedTo().getId() : null,
                t.getDeadline(), t.isEscalated(), t.getPayload(),
                t.getCreatedAt(), t.getUpdatedAt()
        );
    }
}

package com.citybus.platform.service;

import com.citybus.platform.dto.response.RouteSearchResult;
import com.citybus.platform.dto.response.StopSearchResult;
import com.citybus.platform.entity.BusRoute;
import com.citybus.platform.entity.BusStop;
import com.citybus.platform.entity.SortingWeight;
import com.citybus.platform.repository.BusRouteRepository;
import com.citybus.platform.repository.BusStopRepository;
import com.citybus.platform.repository.SortingWeightRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class SearchService {

    private final BusRouteRepository routeRepository;
    private final BusStopRepository stopRepository;
    private final SortingWeightRepository weightRepository;

    @Value("${app.search.max-results:50}")
    private int maxResults;

    @Value("${app.search.autocomplete-max:10}")
    private int autocompleteMax;

    public List<RouteSearchResult> searchRoutes(String query) {
        if (query == null || query.isBlank()) return Collections.emptyList();
        log.info("Route search: query={}", query);
        return routeRepository.searchRoutes(query.trim()).stream()
                .limit(maxResults)
                .map(this::toRouteResult)
                .collect(Collectors.toList());
    }

    public List<StopSearchResult> searchStops(String query, Long routeId) {
        if (query == null || query.isBlank()) return Collections.emptyList();
        log.info("Stop search: query={}, routeId={}", query, routeId);

        List<BusStop> stops;
        if (routeId != null) {
            stops = stopRepository.searchStopsInRoute(query.trim(), routeId);
        } else {
            stops = stopRepository.searchStops(query.trim());
        }

        BigDecimal freqWeight = getWeight("frequency_score");
        BigDecimal popWeight = getWeight("popularity_score");

        return stops.stream()
                .map(s -> toStopResult(s, freqWeight, popWeight))
                .sorted(Comparator.comparingDouble(StopSearchResult::getSortScore).reversed())
                .distinct()
                .limit(maxResults)
                .collect(Collectors.toList());
    }

    public List<String> autocomplete(String query) {
        if (query == null || query.isBlank()) return Collections.emptyList();
        List<String> suggestions = new ArrayList<>();

        stopRepository.autocompleteNames(query.trim())
                .stream().limit(autocompleteMax).forEach(suggestions::add);

        routeRepository.searchRoutes(query.trim()).stream()
                .limit(3)
                .map(r -> r.getRouteNumber() + " - " + r.getName())
                .forEach(suggestions::add);

        return suggestions.stream().distinct().limit(autocompleteMax)
                .collect(Collectors.toList());
    }

    private BigDecimal getWeight(String factorName) {
        return weightRepository.findByFactorName(factorName)
                .map(SortingWeight::getWeight)
                .orElse(BigDecimal.ONE);
    }

    private RouteSearchResult toRouteResult(BusRoute r) {
        return new RouteSearchResult(r.getId(), r.getRouteNumber(), r.getName(),
                r.getDescription(), r.getStatus(),
                r.getStops() != null ? r.getStops().size() : 0);
    }

    private StopSearchResult toStopResult(BusStop s, BigDecimal freqWeight, BigDecimal popWeight) {
        double sortScore = s.getPopularityScore() * popWeight.doubleValue();
        return new StopSearchResult(s.getId(), s.getNameEn(), s.getNameCn(),
                s.getAddress(), s.getSequenceNumber(),
                s.getRoute() != null ? s.getRoute().getId() : null,
                s.getRoute() != null ? s.getRoute().getRouteNumber() : null,
                s.getPopularityScore(), sortScore);
    }
}
package com.citybus.platform.service;

import com.citybus.platform.entity.MessageQueueItem;
import com.citybus.platform.entity.Notification;
import com.citybus.platform.repository.MessageQueueRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Map;

@Service
@RequiredArgsConstructor
@Slf4j
public class MessageQueueService {

    private final MessageQueueRepository queueRepository;
    private final NotificationService notificationService;

    private static final int MAX_RETRIES = 3;

    @Transactional
    public MessageQueueItem enqueue(String type, Map<String, Object> payload, LocalDateTime scheduledAt) {
        MessageQueueItem item = new MessageQueueItem();
        item.setType(type);
        item.setPayload(payload);
        item.setStatus(MessageQueueItem.QueueStatus.PENDING);
        item.setScheduledAt(scheduledAt != null ? scheduledAt : LocalDateTime.now());
        return queueRepository.save(item);
    }

    @Transactional
    public void processPending() {
        List<MessageQueueItem> pending = queueRepository.findPendingMessages(LocalDateTime.now());
        log.debug("Processing {} queued messages", pending.size());
        for (MessageQueueItem item : pending) {
            processItem(item);
        }
    }

    private void processItem(MessageQueueItem item) {
        item.setStatus(MessageQueueItem.QueueStatus.PROCESSING);
        queueRepository.save(item);
        try {
            dispatch(item);
            item.setStatus(MessageQueueItem.QueueStatus.DONE);
            item.setProcessedAt(LocalDateTime.now());
        } catch (Exception e) {
            log.warn("Message {} failed (attempt {}): {}", item.getId(), item.getRetryCount() + 1, e.getMessage());
            item.setRetryCount(item.getRetryCount() + 1);
            item.setError(e.getMessage());
            if (item.getRetryCount() >= MAX_RETRIES) {
                item.setStatus(MessageQueueItem.QueueStatus.FAILED);
            } else {
                item.setStatus(MessageQueueItem.QueueStatus.PENDING);
                item.setScheduledAt(LocalDateTime.now().plusMinutes(5L * item.getRetryCount()));
            }
        }
        queueRepository.save(item);
    }

    private void dispatch(MessageQueueItem item) {
        Map<String, Object> payload = item.getPayload();
        switch (item.getType()) {
            case "NOTIFICATION" -> {
                Long userId = getLong(payload, "userId");
                String typeStr = getString(payload, "notificationType");
                String title = getString(payload, "title");
                String content = getString(payload, "content");
                Long entityId = getLong(payload, "entityId");
                notificationService.createNotification(userId,
                        Notification.NotificationType.valueOf(typeStr), title, content, entityId);
            }
            default -> log.warn("Unknown message type: {}", item.getType());
        }
    }

    public long getPendingCount() {
        return queueRepository.countByStatus(MessageQueueItem.QueueStatus.PENDING);
    }

    private Long getLong(Map<String, Object> map, String key) {
        Object val = map.get(key);
        if (val instanceof Number n) return n.longValue();
        return val != null ? Long.parseLong(val.toString()) : null;
    }

    private String getString(Map<String, Object> map, String key) {
        Object val = map.get(key);
        return val != null ? val.toString() : null;
    }
}

