{"file_path": "/Users/aman/Desktop/projects/TASK-20260318-393C91/repo/frontend/src/api/client.ts", "content": "import axios, { AxiosError } from 'axios';
import type { ApiEnvelope } from '../types';

const client = axios.create({
  baseURL: '',
  headers: { 'Content-Type': 'application/json' },
  timeout: 15000,
});

client.interceptors.request.use((config) => {
  const token = localStorage.getItem('citybus_token');
  if (token && config.headers) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

client.interceptors.response.use(
  (response) => response,
  (error: AxiosError<ApiEnvelope<unknown>>) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('citybus_token');
      localStorage.removeItem('citybus_user');
      if (!window.location.pathname.startsWith('/login')) {
        window.location.href = '/login';
      }
    }
    const msg = error.response?.data?.message || error.message || 'Network error';
    return Promise.reject(new Error(msg));
  },
);

export async function apiGet<T>(url: string, params?: Record<string, unknown>): Promise<T> {
  const res = await client.get<ApiEnvelope<T>>(url, { params });
  return res.data.data;
}

export async function apiPost<T>(url: string, body?: unknown): Promise<T> {
  const res = await client.post<ApiEnvelope<T>>(url, body);
  return res.data.data;
}

export async function apiPatch<T>(url: string, body?: unknown): Promise<T> {
  const res = await client.patch<ApiEnvelope<T>>(url, body);
  return res.data.data;
}

export async function apiDelete<T>(url: string): Promise<T> {
  const res = await client.delete<ApiEnvelope<T>>(url);
  return res.data.data;
}

export async function apiUpload<T>(url: string, formData: FormData): Promise<T> {
  const res = await client.post<ApiEnvelope<T>>(url, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
  return res.data.data;
}

export default client;
"}

{"file_path": "/Users/aman/Desktop/projects/TASK-20260318-393C91/repo/frontend/src/store/AuthContext.tsx", "content": "import { createContext, useCallback, useContext, useMemo, useState, ReactNode } from 'react';
import type { AuthUser } from '../types';
import { apiPost } from '../api/client';

interface AuthContextValue {
  user: AuthUser | null;
  login: (username: string, password: string) => Promise<AuthUser>;
  register: (username: string, password: string, displayName: string) => Promise<AuthUser>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

function loadUser(): AuthUser | null {
  const raw = localStorage.getItem('citybus_user');
  if (!raw) return null;
  try {
    return JSON.parse(raw) as AuthUser;
  } catch {
    return null;
  }
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(loadUser());

  const persist = (u: AuthUser) => {
    localStorage.setItem('citybus_token', u.token);
    localStorage.setItem('citybus_user', JSON.stringify(u));
    setUser(u);
  };

  const login = useCallback(async (username: string, password: string) => {
    const resp = await apiPost<AuthUser>('/api/auth/login', { username, password });
    persist(resp);
    return resp;
  }, []);

  const register = useCallback(async (username: string, password: string, displayName: string) => {
    const resp = await apiPost<AuthUser>('/api/auth/register', { username, password, displayName });
    persist(resp);
    return resp;
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem('citybus_token');
    localStorage.removeItem('citybus_user');
    setUser(null);
  }, []);

  const value = useMemo(() => ({ user, login, register, logout }), [user, login, register, logout]);
  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}
"}

{"file_path": "/Users/aman/Desktop/projects/TASK-20260318-393C91/repo/frontend/src/components/PrivateRoute.tsx", "content": "import { Navigate, useLocation } from 'react-router-dom';
import type { ReactNode } from 'react';
import { useAuth } from '../store/AuthContext';
import type { UserRole } from '../types';

interface Props {
  children: ReactNode;
  roles?: UserRole[];
}

export default function PrivateRoute({ children, roles }: Props) {
  const { user } = useAuth();
  const location = useLocation();

  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }
  if (roles && !roles.includes(user.role)) {
    return <Navigate to="/" replace />;
  }
  return <>{children}</>;
}
"}

