      setItems(res.content);
      const count = await apiGet<number>('/api/notifications/unread-count');
      setUnread(count);
    } catch (e) {
      message.error((e as Error).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const markOne = async (id: number) => {
    await apiPatch(`/api/notifications/${id}/read`);
    load();
  };

  const markAll = async () => {
    await apiPatch('/api/notifications/read-all');
    message.success('All marked as read');
    load();
  };

  return (
    <div className="page-wrapper">
      <Card
        className="page-card"
        title={
          <Space>
            <span>Message center</span>
            <Badge count={unread} />
          </Space>
        }
        extra={
          <Button onClick={markAll} disabled={unread === 0}>
            Mark all read
          </Button>
        }
      >
        <List
          loading={loading}
          dataSource={items}
          locale={{ emptyText: 'No messages yet' }}
          renderItem={(n) => (
            <List.Item
              actions={
                !n.read
                  ? [<Button key="r" size="small" onClick={() => markOne(n.id)}>Mark read</Button>]
                  : [<Tag key="r" color="default">Read</Tag>]
              }
            >
              <List.Item.Meta
                title={
                  <Space>
                    <Tag color={typeColor[n.type] || 'default'}>{n.type.replace(/_/g, ' ')}</Tag>
                    <strong>{n.title}</strong>
                    {!n.read && <Badge status="processing" />}
                  </Space>
                }
                description={
                  <Space direction="vertical" size={2} style={{ width: '100%' }}>
                    <Typography.Text>{n.content}</Typography.Text>
                    <Typography.Text type="secondary" style={{ fontSize: 12 }}>
                      {dayjs(n.createdAt).format('YYYY-MM-DD HH:mm:ss')}
                    </Typography.Text>
                  </Space>
                }
              />
            </List.Item>
          )}
        />
      </Card>
    </div>
  );
}
"}

{"file_path": "/Users/aman/Desktop/projects/TASK-20260318-393C91/repo/frontend/src/pages/passenger/SettingsPage.tsx", "content": "import { useEffect, useState } from 'react';
import { Button, Card, Form, Input, InputNumber, List, Space, Switch, TimePicker, Tag, App as AntdApp } from 'antd';
import dayjs, { Dayjs } from 'dayjs';
import { apiGet, apiPost } from '../../api/client';
import type { NotificationPreference } from '../../types';

interface FormValues {
  routeId?: number;
  stopId?: number;
  reminderMinutes: number;
  enabled: boolean;
  dndEnabled: boolean;
  dndWindow?: [Dayjs, Dayjs];
}

export default function SettingsPage() {
  const { message } = AntdApp.useApp();
  const [items, setItems] = useState<NotificationPreference[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [form] = Form.useForm<FormValues>();
  const dndEnabled = Form.useWatch('dndEnabled', form);

  const load = async () => {
    setLoading(true);
    try {
      const res = await apiGet<NotificationPreference[]>('/api/notifications/preferences');
      setItems(res);
    } catch (e) {
      message.error((e as Error).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
    form.setFieldsValue({ reminderMinutes: 10, enabled: true, dndEnabled: false });
  }, []);

  const submit = async () => {
    try {
      const v = await form.validateFields();
      setSaving(true);
      const body: Record<string, unknown> = {
        routeId: v.routeId || null,
        stopId: v.stopId || null,
        reminderMinutes: v.reminderMinutes,
        enabled: v.enabled,
        dndEnabled: v.dndEnabled,
      };
      if (v.dndEnabled && v.dndWindow) {
        body.dndStart = v.dndWindow[0].format('HH:mm');
        body.dndEnd = v.dndWindow[1].format('HH:mm');
      }
      await apiPost('/api/notifications/preferences', body);
      message.success('Preferences saved');
      load();
    } catch (e) {
      if ((e as { errorFields?: unknown }).errorFields) return;
      message.error((e as Error).message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="page-wrapper">
      <Card className="page-card" title="Add or update a preference">
        <Form form={form} layout="vertical" onFinish={submit}>
          <Space size="large" wrap>
            <Form.Item name="routeId" label="Route ID (optional)">
              <InputNumber placeholder="leave blank for all" style={{ width: 180 }} />
            </Form.Item>
            <Form.Item name="stopId" label="Stop ID (optional)">
              <InputNumber placeholder="leave blank for all" style={{ width: 180 }} />
            </Form.Item>
            <Form.Item
              name="reminderMinutes"
              label="Reminder minutes"
              rules={[{ required: true, message: 'Required' }]}
            >
              <InputNumber min={1} max={60} style={{ width: 120 }} />
            </Form.Item>
            <Form.Item name="enabled" label="Enabled" valuePropName="checked">
              <Switch />
            </Form.Item>
            <Form.Item name="dndEnabled" label="DND" valuePropName="checked">
              <Switch />
            </Form.Item>
            {dndEnabled && (
              <Form.Item
                name="dndWindow"
                label="DND window (HH:mm)"
                rules={[{ required: true, message: 'Pick a window' }]}
              >
                <TimePicker.RangePicker format="HH:mm" />
              </Form.Item>
            )}
          </Space>
          <Button type="primary" htmlType="submit" loading={saving}>
            Save preference
          </Button>
        </Form>
      </Card>

      <Card className="page-card" title="Current preferences" style={{ marginTop: 16 }}>
        <List
          loading={loading}
          dataSource={items}
          locale={{ emptyText: 'No preferences yet — a default 10-minute reminder will apply' }}
          renderItem={(p) => (
            <List.Item>
              <List.Item.Meta
                title={
                  <Space wrap>
                    <Tag color={p.enabled ? 'green' : 'default'}>{p.enabled ? 'enabled' : 'disabled'}</Tag>
                    <span>
                      Route {p.routeId ?? 'any'} / Stop {p.stopId ?? 'any'} — {p.reminderMinutes} min before
                    </span>
                    {p.dndEnabled && p.dndStart && p.dndEnd && (
                      <Tag color="purple">DND {p.dndStart}–{p.dndEnd}</Tag>
                    )}
                  </Space>
                }
              />
            </List.Item>
          )}
        />
      </Card>
    </div>
  );
}
"}

{"file_path": "/Users/aman/Desktop/projects/TASK-20260318-393C91/repo/frontend/src/pages/dispatcher/TaskListPage.tsx", "content": "import { useEffect, useState } from 'react';
import { Button, Card, Form, Input, InputNumber, Modal, Select, Space, Table, Tag, DatePicker, App as AntdApp } from 'antd';
import type { ColumnsType } from 'antd/es/table';
import dayjs, { Dayjs } from 'dayjs';
import { Link } from 'react-router-dom';
import { apiGet, apiPost } from '../../api/client';
import type { Page, WorkflowTaskResponse } from '../../types';

const TASK_TYPES = [
  { value: 'ROUTE_DATA_CHANGE', label: 'Route Data Change' },
  { value: 'REMINDER_RULE_CONFIG', label: 'Reminder Rule Config' },
  { value: 'ABNORMAL_DATA_REVIEW', label: 'Abnormal Data Review' },
];

const STATUSES = ['PENDING', 'APPROVED', 'REJECTED', 'RETURNED', 'ESCALATED', 'CANCELLED'];

const statusColor = (s: string) =>
  s === 'PENDING' ? 'blue'
    : s === 'APPROVED' ? 'green'
    : s === 'REJECTED' ? 'red'
    : s === 'ESCALATED' ? 'volcano'
    : 'default';

export default function TaskListPage() {
  const { message } = AntdApp.useApp();
  const [data, setData] = useState<WorkflowTaskResponse[]>([]);
  const [loading, setLoading] = useState(false);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(0);
  const [size, setSize] = useState(10);
  const [filterStatus, setFilterStatus] = useState<string | undefined>();
  const [modalOpen, setModalOpen] = useState(false);
  const [form] = Form.useForm<{
    type: string; title: string; description?: string;
    assignedToId?: number; deadline?: Dayjs;
  }>();

  const load = async () => {
    setLoading(true);
    try {
      const params: Record<string, unknown> = { page, size };
      if (filterStatus) params.status = filterStatus;
      const res = await apiGet<Page<WorkflowTaskResponse>>('/api/workflow/tasks', params);
      setData(res.content);
      setTotal(res.totalElements);
    } catch (e) {
      message.error((e as Error).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, [page, size, filterStatus]);

  const submit = async () => {
    try {
      const v = await form.validateFields();
      await apiPost('/api/workflow/tasks', {
        type: v.type,
        title: v.title,
        description: v.description,
        assignedToId: v.assignedToId || null,
        deadline: v.deadline ? v.deadline.format('YYYY-MM-DDTHH:mm:ss') : null,
      });
      message.success('Task created');
      setModalOpen(false);
      form.resetFields();
      load();
    } catch (e) {
      if ((e as { errorFields?: unknown }).errorFields) return;
      message.error((e as Error).message);
    }
  };

  const columns: ColumnsType<WorkflowTaskResponse> = [
    { title: 'Task #', dataIndex: 'taskNumber' },
    { title: 'Title', render: (_, t) => <Link to={`/dispatcher/tasks/${t.id}`}>{t.title}</Link> },
    { title: 'Type', dataIndex: 'type', render: (v) => <Tag>{v.replace(/_/g, ' ')}</Tag> },
    {
      title: 'Status',
      dataIndex: 'status',
      render: (s, r) => (
        <Space>
          <Tag color={statusColor(s)}>{s}</Tag>
          {r.escalated && <Tag color="volcano">escalated</Tag>}
        </Space>
      ),
    },
    { title: 'Assigned to', dataIndex: 'assignedToUsername', render: (v) => v || '—' },
    { title: 'Deadline', dataIndex: 'deadline', render: (v) => (v ? dayjs(v).format('YYYY-MM-DD HH:mm') : '—') },
  ];

  return (
    <div className="page-wrapper">
      <Card
        className="page-card"
        title="All tasks"
        extra={
          <Space>
            <Select
              allowClear
              placeholder="Filter by status"
              style={{ width: 180 }}
              options={STATUSES.map((s) => ({ value: s, label: s }))}
              onChange={(v) => { setFilterStatus(v); setPage(0); }}
            />
            <Button type="primary" onClick={() => setModalOpen(true)}>
              New task
            </Button>
          </Space>
        }
      >
        <Table
          rowKey="id"
          loading={loading}
          columns={columns}
          dataSource={data}
          pagination={{
            current: page + 1,
            pageSize: size,
            total,
            onChange: (p, s) => { setPage(p - 1); setSize(s); },
          }}
        />
      </Card>

      <Modal
        title="Create workflow task"
        open={modalOpen}
        onOk={submit}
        onCancel={() => setModalOpen(false)}
        okText="Create"
        destroyOnClose
      >
        <Form form={form} layout="vertical">
          <Form.Item name="type" label="Type" rules={[{ required: true, message: 'Required' }]}>
            <Select options={TASK_TYPES} />
          </Form.Item>
          <Form.Item name="title" label="Title" rules={[{ required: true, message: 'Required' }]}>
            <Input />
          </Form.Item>
          <Form.Item name="description" label="Description">
            <Input.TextArea rows={3} />
          </Form.Item>
          <Form.Item name="assignedToId" label="Assigned to (user ID)">
            <InputNumber style={{ width: '100%' }} />
          </Form.Item>
          <Form.Item name="deadline" label="Deadline">
            <DatePicker showTime style={{ width: '100%' }} />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
"}

